+    fn parse_ibody_xattrs_accepts_value_at_exact_layout_boundary() {
+        let mut buf = vec![0_u8; 256];
+        buf[0x00..0x02].copy_from_slice(&(S_IFREG | 0o644).to_le_bytes());
+        buf[0x80..0x82].copy_from_slice(&32_u16.to_le_bytes());
