+        buf[entry_start + 8..entry_start + 12].copy_from_slice(&3_u32.to_le_bytes());
+        buf[entry_start + 16..entry_start + 20].copy_from_slice(b"mime");
+        buf[ibody_start + usize::from(value_offs)..ibody_start + usize::from(value_offs) + 3]
